<?php
namespace Tests\Unit;
use App\Services\Trading\PortfolioApprovalPolicyService;
use Tests\TestCase;
class PortfolioApprovalPolicyServiceTest extends TestCase
{protected function candidate($status='candidate_ready'):array{return ['schema_version'=>'trading_action_candidate_v1','status'=>$status,'candidate_id'=>'candidate-1','intent'=>'BUY'];}protected function risk($portfolio='evaluated_reference'):array{return ['action_specific_risk'=>['schema_version'=>'trading_action_risk_v1','status'=>'evaluated_reference'],'capital_risk'=>['schema_version'=>'trading_capital_risk_v1','status'=>'evaluated_reference'],'position_sizing'=>['schema_version'=>'trading_position_sizing_v1','status'=>'reference_sized'],'portfolio_risk'=>['schema_version'=>'trading_portfolio_risk_v1','status'=>$portfolio,'portfolio_id'=>'portfolio-1']];}protected function plan($ready='reference_ready'):array{return ['reference_plan'=>['schema_version'=>'trading_reference_trade_plan_v1','status'=>'materialized'],'execution_readiness'=>['schema_version'=>'trading_execution_readiness_v1','status'=>$ready]];}protected function policy(array $over=[]):array{return array_replace_recursive(['schema_version'=>'trading_portfolio_approval_policy_v1','status'=>'reference_only','policy_id'=>'policy-1','policy_version'=>'approval-v1','approval_scope'=>'entry_candidate_reference','portfolio_id'=>'portfolio-1','candidate_id'=>'candidate-1','requirements'=>['candidate_ready'=>true,'action_risk_evaluated'=>true,'reference_plan_materialized'=>true,'capital_risk_evaluated'=>true,'position_sizing_reference_available'=>true,'execution_readiness_reference_available'=>true,'portfolio_risk_evaluated'=>true,'portfolio_limits_passed'=>true,'authorization_required'=>true],'source'=>['type'=>'synthetic_test_fixture','identifier'=>'approval-policy'],'approved_for_production'=>false,'approved_for_execution'=>false,'synthetic_test_only'=>true],$over);}public function test_no_policy_invalid_schema_unknown_requirement_and_identity():void{$svc=new PortfolioApprovalPolicyService();$r=$svc->evaluate(['decision_scope'=>'entry_evaluation','action_candidate'=>$this->candidate(),'risk'=>$this->risk(),'trade_plan'=>$this->plan()]);$this->assertSame('unavailable',$r['status']);foreach([['schema_version'=>'bad'],['approval_scope'=>'bad'],['requirements'=>['confidence_threshold'=>true]],['candidate_id'=>'other']] as $over){$x=$svc->evaluate(['decision_scope'=>'entry_evaluation','action_candidate'=>$this->candidate(),'risk'=>$this->risk(),'trade_plan'=>$this->plan(),'portfolio_approval_policy'=>$this->policy($over)]);$this->assertNotSame('eligible_for_authorization',$x['status']);}}
public function test_requirements_and_eligible_for_authorization():void{$svc=new PortfolioApprovalPolicyService();$ok=$svc->evaluate(['decision_scope'=>'entry_evaluation','action_candidate'=>$this->candidate(),'risk'=>$this->risk(),'trade_plan'=>$this->plan(),'portfolio_approval_policy'=>$this->policy()]);$this->assertSame('eligible_for_authorization',$ok['status']);$this->assertTrue($ok['all_required_checks_passed']);$this->assertFalse(isset($ok['approval_result']));$cases=[[$this->candidate('observation_only'),$this->risk(),$this->plan()],[$this->candidate(),$this->risk('unavailable'),$this->plan()],[$this->candidate(),$this->risk(),$this->plan('unavailable')],[$this->candidate(),$this->risk('limit_exceeded_reference'),$this->plan()]];foreach($cases as [$c,$r,$p]){$res=$svc->evaluate(['decision_scope'=>'entry_evaluation','action_candidate'=>$c,'risk'=>$r,'trade_plan'=>$p,'portfolio_approval_policy'=>$this->policy()]);$this->assertSame('incomplete',$res['status']);}}public function test_deterministic_and_schema_validation():void{$svc=new PortfolioApprovalPolicyService();$a=$svc->evaluate(['decision_scope'=>'entry_evaluation','action_candidate'=>$this->candidate(),'risk'=>$this->risk(),'trade_plan'=>$this->plan(),'portfolio_approval_policy'=>$this->policy()]);$b=$svc->evaluate(['decision_scope'=>'entry_evaluation','action_candidate'=>$this->candidate(),'risk'=>$this->risk(),'trade_plan'=>$this->plan(),'portfolio_approval_policy'=>$this->policy()]);$this->assertSame($a,$b);$this->assertSame('trading_portfolio_approval_policy_evaluation_v1',$a['schema_version']);}}
